{
var input = inputs.Length > 0 ? inputs[0] : null;
        if (input is null)
            return PixelBuffer.CreateSolid(context.TileSize, context.TileSize, 0, 0, 0);

        var blendWidth = GetFloat(parameters, "blendWidth", 0.25f);
        var blendShape = GetChoice(parameters, "blendShape", "linear");
        var blendDirection = GetChoice(parameters, "blendDirection", "both");
        var blendStrength = GetFloat(parameters, "intensity", 1f);
        var showSeam = GetBool(parameters, "showSeam");

        var size = input.Width;
        var halfSize = size / 2;
        var blendPixels = Math.Max(1, (int)(blendWidth * size));

        // Create the offset copy (shifted by half tile in both axes)
        var offset = new PixelBuffer(size, size);
        offset.ParallelForEachPixel((x, y) =>
        {
            var ox = blendDirection == "vertical" ? x : x + halfSize;
            var oy = blendDirection == "horizontal" ? y : y + halfSize;
            var (r, g, b, a) = input.GetPixelWrapped(ox, oy);
            offset.SetPixel(x, y, r, g, b, a);
        });

        // Create the blending mask
        var result = new PixelBuffer(size, size);
        result.ParallelForEachPixel((x, y) =>
        {
            float cx, cy;
            float edgeDistance;

            if (blendDirection == "horizontal")
            {
                cx = MathF.Abs(x - size * 0.5f + 0.5f) / (size * 0.5f);
                edgeDistance = cx;
            }
            else if (blendDirection == "vertical")
            {
                cy = MathF.Abs(y - size * 0.5f + 0.5f) / (size * 0.5f);
                edgeDistance = cy;
            }
            else
            {
                cx = MathF.Abs(x - size * 0.5f + 0.5f) / (size * 0.5f);
                cy = MathF.Abs(y - size * 0.5f + 0.5f) / (size * 0.5f);
                edgeDistance = MathF.Max(cx, cy);
            }

            var blendStart = 1f - blendWidth * 2f;
            float t;
            if (edgeDistance <= blendStart)
            {
                t = 0f;
            }
            else if (edgeDistance >= 1f)
            {
                t = 1f;
            }
            else
            {
                var normalized = (edgeDistance - blendStart) / (1f - blendStart);
                t = blendShape switch
                {
                    "cosine" => 0.5f - 0.5f * MathF.Cos(normalized * MathF.PI),
                    "gaussian" => 1f - MathF.Exp(-normalized * normalized * 4f),
                    "cubic" => normalized * normalized * (3f - 2f * normalized),
                    _ => normalized // linear
                };
            }

            t = Math.Clamp(t * blendStrength, 0f, 1f);

            var (or, og, ob, oa) = input.GetPixelWrapped(x, y);
            var (fr, fg, fb, fa) = offset.GetPixel(x, y);

            var outR = Lerp(or, fr, t);
            var outG = Lerp(og, fg, t);
            var outB = Lerp(ob, fb, t);
            var outA = Lerp(oa, fa, t);

            // Show seam debug line
            if (showSeam)
            {
                var edgePixels = 1f / size;
                if (MathF.Abs(edgeDistance - blendStart) < edgePixels * 2f)
                {
                    outR = 1f; outG = 0f; outB = 0f; outA = 1f;
                }
            }

            result.SetPixel(x, y, outR, outG, outB, outA);
        });

        return result;
}
